window.__QUIZ_DATA__=[{"id":"objective>Geography>2006>1","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the approximate distance by road between toab and oboli","images":["data:image/png;base64,"],"options":{"A":"4.0 kilometers","B":"5.0 kilometers","C":"6.0 kilometers","D":"7.0 kilometers"},"answer":"C","explanation":"From the map, the distance between Toab and Oboli by road is approximately 6.0 kilometres on land in the map of Tarkwa District.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>2","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the approximate distance by road between toab and oboli    The angular bear of shoe from oboli is approximately","images":["data:image/png;base64,"],"options":{"A":"300\u2218","B":"243\u2218","C":"207\u2218","D":"27\u2218"},"answer":"A","explanation":"From the map, the angular bearing of Shoe from Oboli is approximately \"300 \u2218\" because Oboli is located south-east of Shoe in the map of Tarkwa District.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2006>3","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"What is the approximate distance by road between toab and oboli    Which of the following settlement  is not visible from koma","images":["data:image/png;base64,"],"options":{"A":"tarkwa","B":"oboli","C":"shoe","D":"Awow"},"answer":"C","explanation":"From the map, Shoe is not visible from Koma because it is located around rivers,forest and settlements which makes shoe not to be visible from Koma.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>4","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the approximate distance by road between toab and oboli    The major activity of the people in shoe is likely to be","images":["data:image/png;base64,"],"options":{"A":"mining","B":"farming","C":"lumbering","D":"fishing"},"answer":"C","explanation":"Shoe is likely to be a settlement which major activity is Lumbering. This is because many forests are grown there and are used for economic uses in the Tarkwa District.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>5","subject":"Geography","year":"2006","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"What is the approximate distance by road between toab and oboli    which of the following crops can be successfully cultivated around Y?","images":["data:image/png;base64,"],"options":{"A":"Millet","B":"Wheat","C":"coffee","D":"Rice"},"answer":"D","explanation":"From the map, Rice is a crop which is planted around areas that are liable to flooding. In the map, Y is an area viable to flooding.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>6","subject":"Geography","year":"2006","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"What is the approximate distance by road between toab and oboli    Tumpani is important for","images":["data:image/png;base64,"],"options":{"A":"Rice cultivativation","B":"mining","C":"lumbering","D":"cattle rearing"},"answer":"B","explanation":"From the map, Tunpani is a settlements important for mining works because of the minerals located in the area around north-east of Tarkwa District.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>7","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the approximate distance by road between toab and oboli    There are few settlement to the east because of the","images":["data:image/png;base64,"],"options":{"A":"absence of roads","B":"presence of a forest reserve","C":"absence of water resources","D":"predominance of rugged landscape"},"answer":"B","explanation":"From the map, There are few settlements to the east of the Tarwa district because of the presence of forest reserves all over the eastern part of the map.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>8","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the approximate distance by road between toab and oboli    The feature marked X is a","images":["data:image/png;base64,"],"options":{"A":"spur","B":"ridge","C":"cliff","D":"plateau"},"answer":"A","explanation":"From the map, The feature X is a spur.Spurs are projection of highlands into low ground i.e the v-shape points to the lowlands.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>9","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the approximate distance by road between toab and oboli    The area coved by the map is approxiately","images":["data:image/png;base64,"],"options":{"A":"294km3","B":"256km3","C":"190km3","D":"180km3"},"answer":"A","explanation":"The area covered by the map is approximately \"294km\". The map Tarkwa District is covered by the contours of hundred metres in size.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>10","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the approximate distance by road between toab and oboli    The distance between tumpani and Awow's as the crow flies is","images":["data:image/png;base64,"],"options":{"A":"2.50km","B":"4.25km","C":"6.45km","D":"8.25km"},"answer":"D","explanation":"From the map, the distance between Tunpani and Awow as the crow flies is \"8.25km\" according to the map of Tarkwa District.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>11","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The farthest palnet from the sun in the solar system is the","images":[],"options":{"A":"mercury","B":"earth","C":"saturn","D":"pluto"},"answer":"D","explanation":"Pluto is the farthest and coldest planet from the sun. It has the longest orbit around the sun. It takes about 247.7 years to complete its orbit.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2006>12","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following is not a proof to show that the earth is sperical in shape?","images":[],"options":{"A":"sunrise and sunset","B":"aerial photograph","C":"lunar eclipse","D":"twilight and dawn"},"answer":"D","explanation":"Twilight and dawn is not a proof to show that the earth is spherical in shape but is an effect of rotation of the earth. All the remaining options are the proof to show that the earth is spherical in shape.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2006>13","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Latitude 661/2\u2218 S marks the","images":[],"options":{"A":"Anatartic circle","B":"arctic circle","C":"tropic of cancer","D":"tropic of capricon"},"answer":"A","explanation":"Latitude 66\u2218S is located in the earth of the earth called the southern hemisphere. It marks the Antartic circle of the parallels of latitude.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>14","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"What is the distance along a great circle between latitude 27\u2218C and 23.5\u2218N of the equator ?","images":[],"options":{"A":"5,705.5km","B":"5,610.5 km","C":"5,500.5 km","D":"5,405.5 km"},"answer":"C","explanation":"Latitude difference     =27\u2218 + 23.5\u2218=50.5\u2218  Since 1\u2218 =111km  Therefore 50.5\u2218 =111km \u22c6 50.5\u2218                                  =5,605.5km                                  =5,610km","marks":"1","difficulty":"3"},{"id":"objective>Geography>2006>15","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The direction of wind is recorded by an instrument called","images":[],"options":{"A":"anemometer","B":"wind vane","C":"hygrometer","D":"barometer"},"answer":"B","explanation":"The direction of wind is measured by an instrument called Wind vane. Wind vane is made up of two parts. Wind vane is located in an exposed position so that tall building do not deflect the wind direction","marks":"1","difficulty":"1"},{"id":"objective>Geography>2006>16","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Diurnal range of temperature is obtained by","images":[],"options":{"A":"Adding all temperature reading for the day","B":"adding all temperaure reading for the month","C":"substracting the minimum temperature of the day from the maximum temperature of the same day","D":"substrating the minimum temperature for the month from the maximum temperature for the same month"},"answer":"C","explanation":"Diurnal range of temperature is obtained by substracting the minimum temperature of the day from the maximum temperature of the same day.  \u2234Diurnal range =maximum temperature - Minimum temperature for that day.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>17","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"koppen's climatic classification  was based on","images":[],"options":{"A":"rainfall only","B":"the longitude of a place","C":"both rainfall and temperature","D":"latitude of a place"},"answer":"C","explanation":"Kopper system of classification of climate is the best known system of climatic classification. The basis for Kopper\"s classification is temperature and rainfall(precipitation).","marks":"1","difficulty":"3"},{"id":"objective>Geography>2006>18","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The dust particles over which moisture settles when condensation takes place is know as","images":[],"options":{"A":"atmospheric nuclei","B":"hydrocarbon","C":"smoke","D":"nitrogen"},"answer":"B","explanation":"Hydrocarbon are dust particles over which moisture settles when condensation takes place. Hydrocarbon are elements which are often settle when condensation of elements takes place.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>19","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"An example of organically formed sedimentary rocks is","images":[],"options":{"A":"sandstone","B":"rocksalt","C":"traction","D":"plucking"},"answer":"D","explanation":"Organically formed sedimentary rocks are rocks formed from the remains of living organisms. When sedimentary rocks are formed from the remains of animals like corals or shellfish, such rocks are called calcareous rocks, e.g Limestone","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>20","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"A river transport its load through the following process except","images":[],"options":{"A":"soution","B":"suspension","C":"traction","D":"plucking"},"answer":"D","explanation":"Plucking is not a process of river transport. Processes of river transportation are solution, suspension, saltation, trachon. The load of a river is carried or transported along the courte of a river through four main processes.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>21","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The difference between high tide and low tide is referred to as","images":[],"options":{"A":"tidal guage","B":"tidal height","C":"tidal range","D":"tidal flow"},"answer":"C","explanation":"The difference between high tide and low tide is referred to as the tidal range.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>22","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"All the following are found in the upper course of a river except","images":[],"options":{"A":"V-shaped valleys","B":"ox-bow lakes","C":"interlocking spurs","D":"waterfalls"},"answer":"B","explanation":"Waterfalls are not found in the upper course of a river but at the middle course of a river. Features of the upper course of a river include;V-shaped valley, Gorge, River capture","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>23","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"The typical red tropical soil is","images":[],"options":{"A":"deeply weathering in nature with marked A horizon and little humus","B":"Rich in humus, with healthy over head vegetation and high temperature","C":"deeply weathered in nature and rich in humus","D":"rich in humuswith temperature"},"answer":"A","explanation":"The typical red tropical soil is deeply weathered in nature, with marked A-horizon and little humus containing remains of plants and animals undergoing decomposition to form humus.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>24","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"plung pool is a feature of","images":[],"options":{"A":"river meanders","B":"interlocking spurs","C":"waterfalls","D":"water rapids"},"answer":"C","explanation":"Plunge pool is a feature of waterfalls. The water undercuts the softer rocks leading to the receeding of waterfall upstream and formation of plunge pool.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>25","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"All the following are examples of intensive volcanic features except","images":[],"options":{"A":"dykes","B":"sills","C":"lava plateaux","D":"batholiths"},"answer":"C","explanation":"Lava plateaux is not a feature of instrusive volcanoes but a feature of extrusive volcanoes. Dykes and sills are the feature of the intrusive landform of volcanicity.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>26","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The formation of metamorphic rocks normally involves the change of the other rocks though","images":[],"options":{"A":"solution","B":"heat","C":"folding","D":"tension"},"answer":"B","explanation":"Metamorphic rocks are changed rocks. The rocks are formed from pre-existing igneous or sedimentary rocks which have been changed as a result of great heat and pressure.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>27","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Which of the following rocks is used for fuel?","images":[],"options":{"A":"lignite","B":"gianite","C":"diote","D":"mica"},"answer":"A","explanation":"Lignite are sedimentary rocks formed from the remains of vegetable matter such as swamps and forests, they are called Carbonaceous rocks e.g Coal,peat,lignite and petroleum.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2006>28","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"A basin where rock layers have been down folded and in which permeable rock. which has trapped water is sand-wiched between impermeable layers is reffered to as","images":[],"options":{"A":"drainage basin","B":"river basin","C":"water basin","D":"artesian basin"},"answer":"D","explanation":"Artesian basin consists of a layer of permeable rock lying between two layers of impermeable rocks such that the whole forms a shallow syncline with one or both ends of the permeable rock layer exposed to the surface.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2006>29","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following mountains is not a fold mountain ?","images":[],"options":{"A":"The Atlas","B":"the Andes","C":"The Vosges","D":"The Himalayas"},"answer":"B","explanation":"Fold mountains are formed by large scale horizontal earth movement as a result of stress and compressional forces which cause expansion or contraction of some parts of the earth. Examples are;Rockies,Andes, Himalayas,Alps and Atlas mountains.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>30","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"All the following are  featuresproduced by wind erosion except","images":[],"options":{"A":"Rock pdestals","B":"zeugens","C":"rift valleys","D":"yardangs"},"answer":"C","explanation":"Rift valley is not a feature produced by wind erosion. At times, a block in-between two faults may subside so that rift valley or graben is formed. It is a bough between two parallel faults. It has flat bud, at times, irregular floor.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>31","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The meditterrean type of climate is best favured for","images":[],"options":{"A":"yam cultivation","B":"fruit growing","C":"cotton cultivation","D":"wheat production"},"answer":"B","explanation":"The mediterranean type of climate is best favoured for fruit growing because they practice orchard farming and Viticulture which is the cultivation of grape fruits.That is mediterranean type of climate is best favoured for fruit growing.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>32","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"which of the following is north-eastly wind from the sahara blowing towards the gulf of guniea?","images":[],"options":{"A":"The sirocco","B":"the fohn","C":"the harmattan","D":"the chinook"},"answer":"C","explanation":"Harmattan winds are strong,dry,cold and dusty winds. They occur mainly in West Africa. The winds blow from the north east across the Sahara desert towards the Gulf of Guinea.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>33","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Continental shelves are important for all the following except","images":[],"options":{"A":"Fishing","B":"sea piracy","C":"developnment of harbour","D":"recreation"},"answer":"B","explanation":"Sea piracy is not an importance of continental shelf. Continental shelf is a shallow water zone surrounding the continent. It is a good fishing ground, rich in planktons, tourist centres, development of natural harbour.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2006>34","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Spits and bars are formed by","images":[],"options":{"A":"River erosion","B":"wind erosion","C":"wave erosion","D":"wave deposition"},"answer":"D","explanation":"Spits are ridges of sand and gravel formed by long shore drift across the entrance to coastal inlet by lying on one side to the land and the other into the ocean. Ban are formed by wave deposition in shallow sandy water.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>35","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"All the following constitute environmental hazard except?","images":[],"options":{"A":"urbanization","B":"mass wasting","C":"earth quakes","D":"drought"},"answer":"A","explanation":"Urbanization does not constitute environmental harzards. Environmental hazards can be referred to any natural or human induced event which poses a serious danger or risk to the lives and properties of people in their environment. E.g Mass washing, Earthquakes, Drought,soil erosion, pollution e.t.c","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>36","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"The equatorial forest of the amazon basin is generally referred to as the","images":[],"options":{"A":"campos","B":"selvas","C":"pampas","D":"Llanos"},"answer":"A","explanation":"The Equatorial forests of the Amazon basin is generally referred to as the \"Campos\".","marks":"1","difficulty":"1"},{"id":"objective>Geography>2006>37","subject":"Geography","year":"2006","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"xerophytic plants are usually associated with","images":[],"options":{"A":"regions of heavy rainfall","B":"water logging","C":"areas of low rainfall","D":"windward part of highland"},"answer":"C","explanation":"Xerophytic plants are plants found in areas with low rainfall. They do not need water for their growths and survival. They are mostly found i n the deserts.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2006>38","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The total population of the inhabitant of reguon B above is","images":["data:image/png;base64,"],"options":{"A":"300,000","B":"290,000","C":"280,000","D":"270,000"},"answer":"B","explanation":"A dot \".\" represent 10,000 inhabitants. Therefore, the total population of the inhabitants of region B is 29 dots= 29 \u22c6 10,000= 290,000.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>39","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The difference between the population of region A and region C is","images":["data:image/png;base64,"],"options":{"A":"15,000","B":"20,000","C":"25,000","D":"30,000"},"answer":"B","explanation":"The population of region C is 210,000 while population of region A is 190,000.  \u2234The  difference between the population of region A and region C is 210,000 - 190,000 = 20,000","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>40","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"What is the total populaton of A,B and C.","images":["data:image/png;base64,"],"options":{"A":"680,000","B":"550,000","C":"530,000","D":"500,000"},"answer":"A","explanation":"The total population of regions A,B and C is 680,000.  That is, Total population= Population of A + Population of B + Population C                                         = 680,000","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>41","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"'House are far apart from one another . they are commonly conncted by foot path ''. This description refers to","images":[],"options":{"A":"Ribbon sttlement","B":"dispersed settlement","C":"nucleated settlement","D":"urban settlement"},"answer":"B","explanation":"Dispersed or Scattered settlement are the buildings that are scattered or far from each other with few social amenities. E.g Akure and Berger, Shagamu and Alagbole, Ikeja and Berger, e.t.c","marks":"1","difficulty":"1"},{"id":"objective>Geography>2006>42","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"ports that specialize in receiving and redistributing goods to neighbouring countries are called?","images":[],"options":{"A":"Rivers ports","B":"entreport","C":"outports","D":"inlands ports"},"answer":"B","explanation":"Entreports are ports specialize and designed in receiving and redistributing goods to neighbouring countries e.g Ameriaca,Saudi Arabia, China, Nigeria etc are examples of entreports countries.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>43","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"An area is said to be over-populated if","images":[],"options":{"A":"There is not enough food to cater for the population","B":"its inhabitant are not using birth control methods","C":"it has more people than its developed physical and human resources can support","D":"there is massive rural-urban migrtion"},"answer":"C","explanation":"Over population is defined as a situation whereby the population is considered too large for the available resources, for people to enjoy the highest possible standard of living. It is also a situation where the population exceeds the available resources.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>44","subject":"Geography","year":"2006","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"The greatest problem associated with cattle rearing in west africa is","images":[],"options":{"A":"inadequate capital","B":"the absence of high quality cattle","C":"insuffiecient market","D":"the presence of tse-tse fly"},"answer":"D","explanation":"The presence of tse-tse fly is the greatest problem associated with cattle rearing. this is because when a cow is sting by a tse-tse fly it become weak and begins to sleep.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2006>45","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Which of the following is a major benefit of international trade?","images":[],"options":{"A":"total dependence on other countries for essentials goods","B":"Revenue generation","C":"stabilization of prices","D":"Free movement of people across the border"},"answer":"B","explanation":"The major benefits of International Trade is Revenue generation .This is because government generates revenue from imports and exports duties imposed on commodities. Other benefits include; Provision of new products, foreign exchange, employment e.t.c","marks":"1","difficulty":"1"},{"id":"objective>Geography>2006>46","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"perishable good; items of high unit value (gold, diamond) are best transported by","images":[],"options":{"A":"road","B":"rail","C":"air","D":"sea"},"answer":"C","explanation":"Air transportation is the fastest and most expensive means of transportation.It involves the transportation of light goods from one place to another by air. Perishable goods like (gold,diamond) are best transported by air.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>47","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"One of the functions performed by rural settlements for urban settlements is the provision of","images":[],"options":{"A":"employment","B":"agricultural products","C":"manufactured goods","D":"idea and innovations"},"answer":"B","explanation":"Rural settlement provide agricultural produce like corn,millet,cotton etc to the Urban settlement for foreign exchange which will help the rural areas. Functions of rural settlements are;Fishing,farming and Lumbering.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>48","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"which of the following is not a contributio of land transport to the economic developnment of any country?","images":[],"options":{"A":"Generation of income","B":"Employment opportunities","C":"Depopulation of urban centers","D":"Diffusion of ideas and innovations"},"answer":"C","explanation":"Depopulation of urban centres is not a contribution of land transport to the economic development of any country. Contribution of land transport include; Provision of door to door services, It facilitate the movement of people within a short distance.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>49","subject":"Geography","year":"2006","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Which of theseAfrican countries is noted for lumbering ?","images":[],"options":{"A":"Chad","B":"Uganda","C":"Zaire(DRC)","D":"Kenya"},"answer":"C","explanation":"Zaire is an african country which is noted for lumbering. There lumbering areas include Zaire basin, around the provinces of Kinshasa, Ituri and eastern equator. Zaire is one of the best lumbering country in Africa followed by Nigeria.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2006>50","subject":"Geography","year":"2006","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The major causes of change in population size are","images":[],"options":{"A":"Birth,deaths and migration","B":"Birth, marriages and death","C":"Birth, accidents and deaths","D":"migration, fertility and marriage"},"answer":"A","explanation":"The major causes of change in population size are Births (Natality rate) rate at which children are being given birth to in that country,Deaths (mortality rate) rate at which people (both adults and children) die in a country, Migration which is defined as the movement of people from one geographical area to another,involving permanent or temporary residence or settlements.","marks":"1","difficulty":"1"}];